for r_int in range(900, 1000):
    r = r_int / 10000
    centers = []
    dx = 2 * r
    dy = np.sqrt(3) * r

    for row in range(20):
        y = r + row * dy
        if y > 1 - r:
            break
        offset = r if row % 2 == 1 else 0
        for col in range(20):
            x = r + offset + col * dx
            if x > 1 - r:
                break
            centers.append([x, y])

    if len(centers) == 26:
        print(f"r={r:.4f}: {len(centers)} circles, sum={len(centers)*r:.4f}")

